isAuthenticated(): Observable<boolean> {
  return this.getToken()
    .pipe(map((token: NbAuthToken) => token.isValid()));
}

getSelectedItem(tag?: string): Observable<NbMenuBag> {
  const listener = new BehaviorSubject<NbMenuBag>(null);

  getSelectedItem$.next({ tag, listener });

  return listener.asObservable();
}

ngOnDestroy() {
  for (const bucket of this.buckets.values()) {
    this.cancelBucket(bucket);
  }
  this.buckets.clear();
  this.callbackBucket.clear();
}

if (attr.name.startsWith('#')) {
  return {
    name: attr.name.slice(1),
    orderType: OrderType.TemplateReferenceVariable,
  };
}

return children.some(
  (child) =>
    child instanceof TmplAstElement &&
    (child.name === childNodeName || traverseChildNodes(child)),
);

export function assertInjectImplementationNotEqual(
  fn: <T>(token: ProviderToken<T>, flags?: InternalInjectFlags) => T | null,
) {
  ngDevMode &&
    assertNotEqual(_injectImplementation, fn, 'Calling ɵɵinject would cause infinite recursion');
}

export function wrapIntoPromise<T>(value: T | Promise<T> | Observable<T>): Promise<T> {
  if (isObservable(value)) {
    return firstValueFrom(value);
  }
  return Promise.resolve(value);
}

if (parent && !isElement(parent) && !isNgTemplate(parent)) {
  return getNextElementOrTemplateParent(
    parent as unknown as StronglyTypedI18n<TmplAstNode>,
  );
}
